#!/usr/bin/env python3
from __future__ import annotations

import argparse
import csv
import json
import os
import re
import tempfile
from datetime import datetime
from pathlib import Path
from typing import Any

ROOT = Path(__file__).resolve().parents[1]
REPORT_DIR = ROOT / "research" / "reports"
SCHEMA_VERSION = "v0.3"

REQUIRED_INPUT_LABELS = [
    "control_tower",
    "strategy_performance_panel",
    "strategy_governance_gate",
    "daily_strategy_audit",
]

INPUT_FILES = {
    "control_tower": REPORT_DIR / "control_tower_daily_latest.json",
    "strategy_performance_panel": REPORT_DIR / "strategy_performance_panel_latest.json",
    "strategy_governance_gate": REPORT_DIR / "strategy_governance_gate_latest.json",
    "daily_strategy_audit": REPORT_DIR / "daily_strategy_audit_latest.json",
    "today_stock_strategy_report": REPORT_DIR / "today_stock_strategy_report_latest.json",
    "incident_registry": REPORT_DIR / "incident_registry_latest.json",
    "manual_review_closure_alert": REPORT_DIR / "manual_review_closure_alert_latest.json",
    "role_output_archive": REPORT_DIR / "role_output_archive_latest.json",
    "breadth_aggressive": REPORT_DIR / "breadth_aggressive_paper_latest.json",
    "breadth_strict_oos": REPORT_DIR / "breadth_strict_oos_paper_latest.json",
}

ACCEPTANCE_LABELS = {
    "P0-3_manual_intervention_audit": "P0-3 人工干预留痕：还缺连续 5 个交易日真实样本",
    "P2-1_data_snapshot_and_versioning": "P2-1 数据快照与复现：还缺 snapshot 回放作业与 6 个月历史回放验收",
    "P2-3_role_outputs_archival": "P2-3 角色产出归档：还缺连续 4 周覆盖闭环",
}


def atomic_write_text(path: Path, content: str, *, encoding: str = "utf-8") -> None:
    path.parent.mkdir(parents=True, exist_ok=True)
    with tempfile.NamedTemporaryFile("w", encoding=encoding, dir=str(path.parent), delete=False) as handle:
        handle.write(content)
        tmp_path = Path(handle.name)
    os.replace(tmp_path, path)


def atomic_write_json(path: Path, payload: Any) -> None:
    atomic_write_text(path, json.dumps(payload, ensure_ascii=False, indent=2), encoding="utf-8")


def load_json(path: Path | None) -> dict[str, Any]:
    if path is None or not path.exists():
        return {}
    return json.loads(path.read_text(encoding="utf-8"))


def load_csv_rows(path: Path | None) -> list[dict[str, Any]]:
    if path is None or not path.exists():
        return []
    with path.open("r", encoding="utf-8-sig", newline="") as handle:
        return list(csv.DictReader(handle))


def to_float(value: Any, default: float = 0.0) -> float:
    if value in (None, ""):
        return default
    try:
        return float(value)
    except (TypeError, ValueError):
        return default


def basename(path: str) -> str:
    return Path(str(path)).name if path else ""


def latest_file(pattern: str) -> Path | None:
    files = sorted(REPORT_DIR.glob(pattern), key=lambda p: p.stat().st_mtime)
    return files[-1] if files else None


def resolve_latest_json(path: Path, pattern: str) -> Path | None:
    if path.exists():
        return path
    return latest_file(pattern)


def normalize_status(value: Any) -> str:
    text = str(value or "").strip().upper()
    if text in {"PASS", "GREEN", "OK"}:
        return "GREEN"
    if text in {"FAIL", "RED", "BLOCK"}:
        return "BLOCK"
    if text in {"YELLOW", "WARN", "WARNING", "PARTIAL"}:
        return "YELLOW"
    return text or "UNKNOWN"


def normalize_date_tag(value: Any) -> str:
    text = str(value or "").strip()
    if re.fullmatch(r"\d{8}", text):
        return text
    m = re.search(r"(20\d{2})[-_/]?(\d{2})[-_/]?(\d{2})", text)
    if m:
        return f"{m.group(1)}{m.group(2)}{m.group(3)}"
    return ""


def guess_trade_date_tag(today_report: dict[str, Any], control_tower: dict[str, Any], daily_audit: dict[str, Any], remediation: dict[str, Any]) -> str:
    return (
        normalize_date_tag(today_report.get("date_tag"))
        or normalize_date_tag(((control_tower.get("strategy_layer") or {}).get("expected_trade_date_tag")))
        or normalize_date_tag(daily_audit.get("date_tag"))
        or normalize_date_tag(remediation.get("report_date"))
        or datetime.now().strftime("%Y%m%d")
    )


def to_trade_date(date_tag: str) -> str:
    if re.fullmatch(r"\d{8}", date_tag):
        return f"{date_tag[:4]}-{date_tag[4:6]}-{date_tag[6:8]}"
    return date_tag


def summarize_profiles(panel: dict[str, Any]) -> tuple[list[dict[str, Any]], list[dict[str, Any]]]:
    rows = panel.get("rows") or []
    main_profiles: list[dict[str, Any]] = []
    breadth_profiles: list[dict[str, Any]] = []
    for row in rows:
        slim = {
            "profile_slug": row.get("profile_slug"),
            "profile_name": row.get("profile_name"),
            "short_name": row.get("short_name"),
            "date_tag": row.get("date_tag"),
            "status": row.get("status"),
            "tomorrow_mode": row.get("tomorrow_mode"),
            "nav": row.get("nav"),
            "total_return_pct": row.get("total_return_pct"),
            "day_pnl": row.get("day_pnl"),
            "drawdown_pct": row.get("drawdown_pct"),
            "cash": row.get("cash"),
            "market_value": row.get("market_value"),
            "position_count": row.get("position_count"),
            "today_trade_count": row.get("today_trade_count"),
            "issue_codes": row.get("issue_codes"),
        }
        slug = str(row.get("profile_slug") or "")
        if slug.startswith("breadth_"):
            breadth_profiles.append(slim)
        else:
            main_profiles.append(slim)
    return main_profiles, breadth_profiles


def normalize_holding_item(item: dict[str, Any], *, nav: float, buy_date: str = "") -> dict[str, Any]:
    qty = to_float(item.get("qty") or item.get("shares"))
    avg_price = to_float(item.get("avg_price"))
    current_price = to_float(item.get("current_price"))
    current_value = to_float(item.get("current_value"))
    pnl_amount = item.get("pnl_amount")
    pnl_pct = item.get("pnl_pct")
    if pnl_amount in (None, "") and qty > 0 and avg_price > 0 and current_price > 0:
        pnl_amount = round((current_price - avg_price) * qty, 2)
    if pnl_pct in (None, "") and avg_price > 0 and current_price > 0:
        pnl_pct = round((current_price / avg_price - 1.0) * 100.0, 2)
    weight_pct = round(current_value / nav * 100.0, 2) if nav > 0 and current_value > 0 else None
    return {
        "ts_code": str(item.get("ts_code") or item.get("symbol") or ""),
        "name": str(item.get("name") or item.get("stock_name") or ""),
        "qty": int(qty) if qty else 0,
        "avg_price": round(avg_price, 4) if avg_price else None,
        "current_price": round(current_price, 4) if current_price else None,
        "current_value": round(current_value, 2) if current_value else 0.0,
        "weight_pct": weight_pct,
        "pnl_amount": round(to_float(pnl_amount), 2) if pnl_amount not in (None, "") else None,
        "pnl_pct": round(to_float(pnl_pct), 2) if pnl_pct not in (None, "") else None,
        "buy_date": str(item.get("buy_date") or buy_date or ""),
    }


def load_single_profile_holdings(row: dict[str, Any]) -> dict[str, Any]:
    slug = str(row.get("profile_slug") or "")
    display_name = str(row.get("short_name") or row.get("profile_name") or slug)
    entry: dict[str, Any] = {
        "profile_slug": slug,
        "profile_name": display_name,
        "profile_full_name": str(row.get("profile_name") or display_name),
        "status": str(row.get("status") or ""),
        "position_count": int(to_float(row.get("position_count"))),
        "is_single_profile": True,
        "source_label": "单一模拟盘",
        "source_kind": "single_profile",
        "source_files": [],
        "holdings": [],
    }

    if slug.startswith("breadth_"):
        summary_path = REPORT_DIR / f"{slug}_paper_latest.json"
        payload = load_json(summary_path)
        total_value = to_float(payload.get("total_value"))
        entry["source_files"] = [str(summary_path)] if summary_path.exists() else []
        entry["date_tag"] = normalize_date_tag(payload.get("signal_date") or payload.get("current_date") or row.get("date_tag"))
        holdings = [
            normalize_holding_item(
                {
                    "symbol": item.get("symbol"),
                    "name": item.get("name"),
                    "shares": item.get("shares"),
                    "avg_price": item.get("avg_price"),
                    "current_price": item.get("current_price"),
                    "current_value": item.get("current_value"),
                    "buy_date": item.get("buy_date"),
                },
                nav=total_value,
            )
            for item in (payload.get("holdings") or [])
        ]
    else:
        account_path = REPORT_DIR / f"paper_{slug}_account_v1_latest.json"
        positions_cn_path = REPORT_DIR / f"paper_{slug}_portfolio_positions_latest_cn.csv"
        positions_path = positions_cn_path if positions_cn_path.exists() else REPORT_DIR / f"paper_{slug}_portfolio_positions_latest.csv"
        account = load_json(account_path)
        nav = to_float(account.get("nav"))
        rows = load_csv_rows(positions_path)
        entry["source_files"] = [str(path) for path in [account_path, positions_path] if path.exists()]
        entry["date_tag"] = normalize_date_tag(account.get("date_tag") or row.get("date_tag"))
        holdings = [
            normalize_holding_item(
                {
                    "ts_code": item.get("股票代码") or item.get("ts_code") or item.get("symbol"),
                    "name": item.get("股票名称") or item.get("stock_name") or item.get("name"),
                    "qty": item.get("持仓数量") or item.get("qty") or item.get("shares"),
                    "avg_price": item.get("成本价") or item.get("avg_price") or item.get("cost_price"),
                    "current_price": item.get("最新价") or item.get("current_price") or item.get("price"),
                    "current_value": item.get("持仓市值") or item.get("market_value") or item.get("position_value"),
                    "pnl_amount": item.get("浮盈亏") or item.get("pnl") or item.get("unrealized_pnl"),
                    "pnl_pct": item.get("浮盈亏比例(%)") or item.get("pnl_pct") or item.get("unrealized_pnl_pct"),
                    "buy_date": item.get("买入日期") or item.get("buy_date"),
                },
                nav=nav,
            )
            for item in rows
        ]

    entry["holdings"] = sorted(holdings, key=lambda item: (-to_float(item.get("current_value")), str(item.get("ts_code") or "")))
    return entry


def build_profile_holdings(panel: dict[str, Any]) -> list[dict[str, Any]]:
    rows = panel.get("rows") or []
    groups = {"current_paper", "legacy_paper", "breadth_experimental"}
    return [load_single_profile_holdings(row) for row in rows if str(row.get("group") or "") in groups]


def build_candidate_source_summary(today_report: dict[str, Any]) -> dict[str, Any]:
    priority_rows = (today_report.get("priority_candidates") or []) + (today_report.get("research_priority_candidates") or [])
    source_files: list[str] = []
    merged_signals_path = str(((today_report.get("source_files") or {}).get("merged_signals_csv")) or "")
    if merged_signals_path:
        source_files.append(merged_signals_path)
    for row in priority_rows:
        source_file = str(row.get("source_signal_file") or "")
        if source_file and source_file not in source_files:
            source_files.append(source_file)
    strategy_ids: list[str] = []
    for row in priority_rows:
        strategy_id = str(row.get("strategy_id") or "").strip()
        if strategy_id and strategy_id not in strategy_ids:
            strategy_ids.append(strategy_id)
    return {
        "is_single_profile": False,
        "source_label": "非单一模拟盘（合并信号池/候选池）",
        "source_kind": "merged_signal_pool" if any("merged_signals" in item for item in source_files) else "candidate_pool",
        "source_files": source_files,
        "source_file_names": [basename(item) for item in source_files],
        "strategy_ids": strategy_ids,
        "buy_candidates": today_report.get("buy_candidates"),
        "research_buy_candidates": today_report.get("research_buy_candidates"),
        "sell_candidates": today_report.get("sell_candidates"),
    }


def build_acceptance_watchlist(remediation: dict[str, Any], role_output_archive: dict[str, Any]) -> list[dict[str, Any]]:
    items = remediation.get("items") or {}
    evidence = remediation.get("evidence") or {}
    watchlist: list[dict[str, Any]] = []
    for key in remediation.get("next_priority") or []:
        status = str(items.get(key) or "").strip().lower()
        if status not in {"partial", "block", "blocked"}:
            continue
        entry = {
            "key": key,
            "status": status,
            "summary": ACCEPTANCE_LABELS.get(key, key),
            "evidence": evidence.get(
                {
                    "P0-3_manual_intervention_audit": "p0_3_progress_report",
                    "P2-1_data_snapshot_and_versioning": "p2_1_progress_report",
                    "P2-3_role_outputs_archival": "p2_3_progress_report",
                }.get(key, ""),
                "",
            ),
        }
        if key == "P2-3_role_outputs_archival":
            coverage = {}
            for role in role_output_archive.get("roles") or []:
                coverage[str(role.get("role") or "")] = {
                    "covered_week_count": role.get("covered_week_count"),
                    "meets_4week_requirement": role.get("meets_4week_requirement"),
                }
            entry["coverage"] = coverage
        watchlist.append(entry)
    return watchlist


def infer_input_date_tag(label: str, payload: dict[str, Any]) -> str:
    candidates = []
    if label == "control_tower":
        candidates = [
            ((payload.get("strategy_layer") or {}).get("expected_trade_date_tag")),
            payload.get("date_tag"),
        ]
    elif label == "strategy_performance_panel":
        rows = payload.get("rows") or []
        if rows:
            candidates = [rows[0].get("date_tag")]
    elif label == "strategy_governance_gate":
        candidates = [payload.get("date_tag"), payload.get("trade_date_tag")]
    elif label == "daily_strategy_audit":
        candidates = [payload.get("date_tag")]
    elif label == "today_stock_strategy_report":
        candidates = [payload.get("date_tag")]
    elif label == "incident_registry":
        candidates = [payload.get("date_tag"), payload.get("report_date")]
    elif label == "manual_review_closure_alert":
        candidates = [payload.get("date_tag"), payload.get("report_date")]
    elif label == "role_output_archive":
        candidates = [payload.get("date_tag"), payload.get("report_date")]
    return next((normalize_date_tag(item) for item in candidates if normalize_date_tag(item)), "")


def file_entry(label: str, path: Path | None, payload: dict[str, Any], *, required: bool, trade_date_tag: str) -> dict[str, Any]:
    if path is None:
        return {
            "label": label,
            "required": required,
            "exists": False,
            "path": "",
            "mtime": "",
            "input_date_tag": "",
            "date_match": False,
            "freshness_status": "MISSING",
        }
    exists = path.exists()
    input_date_tag = infer_input_date_tag(label, payload) if exists else ""
    date_match = bool(input_date_tag) and input_date_tag == trade_date_tag
    freshness_status = "MISSING"
    if exists:
        freshness_status = "MATCH" if date_match else ("UNKNOWN" if not input_date_tag else "MISMATCH")
    return {
        "label": label,
        "required": required,
        "exists": exists,
        "path": str(path),
        "mtime": datetime.fromtimestamp(path.stat().st_mtime).strftime("%Y-%m-%d %H:%M:%S") if exists else "",
        "input_date_tag": input_date_tag,
        "date_match": date_match,
        "freshness_status": freshness_status,
    }


def build_delivery_summary_filename(trade_date_tag: str) -> dict[str, str]:
    return {
        "feishu_summary_latest": str(REPORT_DIR / "daily_quant_analysis_feishu_latest.txt"),
        "feishu_summary_dated": str(REPORT_DIR / f"daily_quant_analysis_feishu_{trade_date_tag}.txt"),
    }


def main() -> None:
    parser = argparse.ArgumentParser(description="Build structured daily quant analysis JSON artifact")
    parser.add_argument("--date-tag", default="", help="Optional explicit trade date tag (YYYYMMDD)")
    args = parser.parse_args()

    control_tower_path = resolve_latest_json(INPUT_FILES["control_tower"], "control_tower_daily_*.json")
    panel_path = resolve_latest_json(INPUT_FILES["strategy_performance_panel"], "strategy_performance_panel_*.json")
    gate_path = resolve_latest_json(INPUT_FILES["strategy_governance_gate"], "strategy_governance_gate_*.json")
    daily_audit_path = resolve_latest_json(INPUT_FILES["daily_strategy_audit"], "daily_strategy_audit_*.json")
    today_report_path = resolve_latest_json(INPUT_FILES["today_stock_strategy_report"], "today_stock_strategy_report_*.json")
    incident_path = resolve_latest_json(INPUT_FILES["incident_registry"], "incident_registry_*.json")
    closure_path = resolve_latest_json(INPUT_FILES["manual_review_closure_alert"], "manual_review_closure_alert_*.json")
    archive_path = resolve_latest_json(INPUT_FILES["role_output_archive"], "role_output_archive_*.json")
    remediation_path = latest_file("remediation_roadmap_alignment_report_*.json")
    detailed_report_path = latest_file("selfcheck_and_remediation_detailed_report_*.json")

    control_tower = load_json(control_tower_path)
    panel = load_json(panel_path)
    gate = load_json(gate_path)
    daily_audit = load_json(daily_audit_path)
    today_report = load_json(today_report_path)
    incident_registry = load_json(incident_path)
    manual_review_closure = load_json(closure_path)
    role_output_archive = load_json(archive_path)
    remediation = load_json(remediation_path)
    detailed_report = load_json(detailed_report_path)

    trade_date_tag = args.date_tag.strip() or guess_trade_date_tag(today_report, control_tower, daily_audit, remediation)
    trade_date = to_trade_date(trade_date_tag)
    generated_at = datetime.now().strftime("%Y-%m-%d %H:%M:%S")

    required_payloads = {
        "control_tower": control_tower,
        "strategy_performance_panel": panel,
        "strategy_governance_gate": gate,
        "daily_strategy_audit": daily_audit,
    }
    required_paths = {
        "control_tower": control_tower_path,
        "strategy_performance_panel": panel_path,
        "strategy_governance_gate": gate_path,
        "daily_strategy_audit": daily_audit_path,
    }
    optional_payloads = {
        "today_stock_strategy_report": today_report,
        "incident_registry": incident_registry,
        "manual_review_closure_alert": manual_review_closure,
        "role_output_archive": role_output_archive,
        "remediation_roadmap": remediation,
        "selfcheck_detailed_report": detailed_report,
    }
    optional_paths = {
        "today_stock_strategy_report": today_report_path,
        "incident_registry": incident_path,
        "manual_review_closure_alert": closure_path,
        "role_output_archive": archive_path,
        "remediation_roadmap": remediation_path,
        "selfcheck_detailed_report": detailed_report_path,
    }

    required_inputs = {
        label: file_entry(label, required_paths.get(label), required_payloads.get(label) or {}, required=True, trade_date_tag=trade_date_tag)
        for label in REQUIRED_INPUT_LABELS
    }
    optional_inputs = {
        label: file_entry(label, optional_paths.get(label), optional_payloads.get(label) or {}, required=False, trade_date_tag=trade_date_tag)
        for label in [
            "today_stock_strategy_report",
            "incident_registry",
            "manual_review_closure_alert",
            "role_output_archive",
            "remediation_roadmap",
            "selfcheck_detailed_report",
        ]
    }

    missing_required = [label for label, meta in required_inputs.items() if not meta["exists"]]
    mismatched_required = [label for label, meta in required_inputs.items() if meta["exists"] and meta["freshness_status"] == "MISMATCH"]
    unknown_required = [label for label, meta in required_inputs.items() if meta["exists"] and meta["freshness_status"] == "UNKNOWN"]

    governance_blocking = bool(gate.get("blocking_issues")) or str(gate.get("overall_status") or "").upper() not in {"PASS", "GREEN"}
    control_status = normalize_status(control_tower.get("overall_status"))
    remediation_status = normalize_status(remediation.get("overall_status")) if remediation else "UNKNOWN"

    if missing_required or mismatched_required:
        overall_status = "BLOCK"
    elif governance_blocking:
        overall_status = "BLOCK"
    elif control_status == "BLOCK":
        overall_status = "BLOCK"
    elif control_status == "YELLOW" or remediation_status == "YELLOW" or unknown_required:
        overall_status = "YELLOW"
    else:
        overall_status = "GREEN"

    main_profiles, breadth_profiles = summarize_profiles(panel)
    profile_holdings = build_profile_holdings(panel)
    candidate_source_summary = build_candidate_source_summary(today_report)
    acceptance_watchlist = build_acceptance_watchlist(remediation, role_output_archive)

    payload = {
        "schema_version": SCHEMA_VERSION,
        "report_kind": "daily_quant_analysis_skill",
        "trade_date_tag": trade_date_tag,
        "trade_date": trade_date,
        "generated_at": generated_at,
        "overall_status": overall_status,
        "delivery_ready": not missing_required and not mismatched_required,
        "data_freshness": {
            "status": "BLOCK" if (missing_required or mismatched_required) else ("YELLOW" if unknown_required else "GREEN"),
            "missing_required_inputs": missing_required,
            "mismatched_required_inputs": mismatched_required,
            "unknown_required_inputs": unknown_required,
            "required_inputs": required_inputs,
            "optional_inputs": optional_inputs,
        },
        "trading": {
            "trading_status": ((control_tower.get("trading_status") or {}).get("status")) or ((control_tower.get("strategy_layer") or {}).get("trading_status")) or today_report.get("precheck_status"),
            "trading_reason": ((control_tower.get("trading_status") or {}).get("reason")) or ((control_tower.get("strategy_layer") or {}).get("trading_status_reason")) or today_report.get("halt_reason"),
            "recommendation_state": ((today_report.get("recommendation_status") or {}).get("state")) or "",
            "execution_scope": daily_audit.get("execution_scope") or "",
        },
        "governance": {
            "status": str(gate.get("overall_status") or "UNKNOWN"),
            "blocking": governance_blocking,
            "blocking_issues": gate.get("blocking_issues") or [],
            "generated_at": gate.get("generated_at") or "",
        },
        "execution": {
            "status": ((control_tower.get("execution_layer") or {}).get("trading_status")) or "",
            "reason": ((control_tower.get("execution_layer") or {}).get("trading_status_reason")) or "",
            "live_tomorrow_mode": ((control_tower.get("execution_layer") or {}).get("live_tomorrow_mode")) or "",
            "live_orders_total": ((control_tower.get("execution_layer") or {}).get("live_orders_total")),
            "live_pending_confirm_not_sent": ((control_tower.get("execution_layer") or {}).get("live_pending_confirm_not_sent")),
            "live_not_sent": ((control_tower.get("execution_layer") or {}).get("live_not_sent")),
        },
        "profiles": main_profiles,
        "breadth_profiles": breadth_profiles,
        "profile_holdings": profile_holdings,
        "candidate_source_summary": candidate_source_summary,
